module median_filter (
    input [7:0] a,
    input [7:0] b,
    input [7:0] c,
    input [7:0] d,
    input [7:0] e,
    output reg [7:0] median
);

reg [7:0] unused_sorted [0:4];

integer i, j;

always @(*) begin
    // Load inputs into unused_sorted array
    unused_sorted[0] = a;
    unused_sorted[1] = b;
    unused_sorted[2] = c;
    unused_sorted[3] = d;
    unused_sorted[4] = e;

    // Simple bubble sort to sort the array
    for (i = 0; i < 4; i = i + 1) begin
        for (j = 0; j < 4 - i; j = j + 1) begin
            if (unused_sorted[j] > unused_sorted[j + 1]) begin
                // Swap
                {unused_sorted[j], unused_sorted[j + 1]} = {unused_sorted[j + 1], unused_sorted[j]};
            end
        end
    end

    // Select the median (the middle element in the unused_sorted array)
    median = unused_sorted[2];
end

endmodule
